import { NextRequest, NextResponse } from "next/server";
import { prisma } from "@/lib/prisma";

// Common job title patterns for generating keyword suggestions (pre-computed for speed)
const JOB_TITLE_PREFIXES = [
    "nhân viên", "chuyên viên", "trưởng phòng", "phó trưởng phòng", "trưởng nhóm",
    "senior", "junior", "lead", "head", "director", "manager", "executive",
    "intern", "thực tập sinh", "assistant", "coordinator", "specialist", "supervisor"
];

const JOB_TITLE_SUFFIXES = [
    "online", "digital", "content", "social media", "email", "seo", "brand",
    "mobile", "web", "frontend", "backend", "fullstack", "devops", "data",
    "business", "sales", "marketing", "it", "hr", "finance", "accounting",
    "customer service", "operation", "project", "product", "design", "engineer"
];

// Common related keywords mapping (pre-computed for speed)
const RELATED_KEYWORDS_MAP: Record<string, string[]> = {
    "dev": ["frontend developer", "backend developer", "fullstack developer", "mobile developer", "web developer", "react developer", "nodejs developer"],
    "developer": ["frontend developer", "backend developer", "fullstack developer", "mobile developer", "web developer", "react developer", "vue developer"],
    "design": ["ui designer", "ux designer", "graphic designer", "web designer", "product designer", "motion designer", "visual designer"],
    "market": ["digital marketing", "content marketing", "social media marketing", "email marketing", "seo marketing", "marketing online"],
    "marketing": ["digital marketing", "content marketing", "social media marketing", "email marketing", "seo marketing", "brand marketing"],
    "sale": ["sales executive", "sales manager", "sales representative", "business development", "account executive", "sales coordinator"],
    "sales": ["sales executive", "sales manager", "sales representative", "business development", "account executive", "sales coordinator"],
    "it": ["it support", "it administrator", "it manager", "it security", "it project", "system administrator"],
    "hr": ["hr manager", "hr specialist", "hr coordinator", "recruiter", "nhân sự", "tuyển dụng"],
    "account": ["kế toán", "tài chính", "accountant", "finance manager", "accounting staff"],
    "ke toán": ["kế toán tổng hợp", "kế toán thanh toán", "kế toán kho", "kế toán công nợ"],
    "tai chính": ["tài chính doanh nghiệp", "tài chính kế toán", "finance manager", "financial analyst"],
    "customer": ["customer service", "chăm sóc khách hàng", "customer support", "tư vấn", "sales"],
    "project": ["project manager", "project coordinator", "quản lý dự án", "project executive"],
    "product": ["product manager", "product owner", "quản lý sản phẩm", "product marketing"],
    "content": ["content writer", "content marketing", "content creator", "copywriter", "biên tập viên"],
    "data": ["data analyst", "data scientist", "data engineer", "business analyst", "phân tích dữ liệu"],
    "operation": ["vận hành", "operation manager", "operations coordinator", "quản lý vận hành"],
    "admin": ["admin staff", "nhân viên hành chính", "admin assistant", "hành chính văn phòng"],
    "engineer": ["software engineer", "mechanical engineer", "electrical engineer", "civil engineer", "qa engineer"],
    "manager": ["project manager", "product manager", "sales manager", "marketing manager", "hr manager", "finance manager"],
};

export async function GET(request: NextRequest) {
    try {
        const searchParams = request.nextUrl.searchParams;
        const query = searchParams.get("q")?.toLowerCase().trim() || "";

        if (query.length < 2) {
            // Return popular searches when query is empty or too short
            const popularSearches = await getPopularSearches();
            return NextResponse.json({ suggestions: popularSearches });
        }

        const suggestions: Array<{ type: string; value: string; label: string }> = [];

        // 1. Generate keyword suggestions (từ khoá gợi ý) - fast local computation
        const keywordSuggestions = generateKeywordSuggestionsFast(query);
        keywordSuggestions.forEach(keyword => {
            suggestions.push({
                type: "keyword_suggestion",
                value: keyword,
                label: keyword,
            });
        });

        // 2. Generate related keywords (từ khoá liên quan) - fast local computation
        const relatedKeywords = generateRelatedKeywordsFast(query);
        relatedKeywords.forEach(keyword => {
            suggestions.push({
                type: "related_keyword",
                value: keyword,
                label: keyword,
            });
        });

        // 3. Search for matching job titles from database (very fast with index)
        const jobs = await prisma.job.findMany({
            where: {
                status: "ACTIVE",
                title: { contains: query, mode: "insensitive" },
            },
            select: { title: true },
            distinct: ["title"],
            take: 5,
            orderBy: { viewCount: "desc" },
        });

        jobs.forEach(job => {
            suggestions.push({
                type: "job_title",
                value: job.title,
                label: job.title,
            });
        });

        // 4. Search for matching skills from database (very fast with index)
        const skills = await prisma.skill.findMany({
            where: {
                name: { contains: query, mode: "insensitive" },
            },
            select: { name: true },
            take: 5,
        });

        skills.forEach(skill => {
            suggestions.push({
                type: "skill",
                value: skill.name,
                label: skill.name,
            });
        });

        // 5. Search for matching industries from database (very fast with index)
        const industries = await prisma.industry.findMany({
            where: {
                name: { contains: query, mode: "insensitive" },
            },
            select: { name: true },
            take: 3,
        });

        industries.forEach(industry => {
            suggestions.push({
                type: "industry",
                value: industry.name,
                label: industry.name,
            });
        });

        // Limit total suggestions
        return NextResponse.json({ suggestions: suggestions.slice(0, 20) });
    } catch (error) {
        console.error("Suggestions API error:", error);
        return NextResponse.json({ suggestions: [], error: "Lỗi server" }, { status: 500 });
    }
}

// Fast keyword suggestions generation using pre-computed patterns
function generateKeywordSuggestionsFast(query: string): string[] {
    const suggestions: string[] = [];

    // Add prefix + query (e.g., "senior" + "marketing" = "senior marketing")
    JOB_TITLE_PREFIXES.forEach(prefix => {
        suggestions.push(`${prefix} ${query}`);
    });

    // Add query + suffix (e.g., "marketing" + "online" = "marketing online")
    JOB_TITLE_SUFFIXES.forEach(suffix => {
        suggestions.push(`${query} ${suffix}`);
    });

    // Deduplicate and return
    return [...new Set(suggestions)].slice(0, 8);
}

// Fast related keywords generation using pre-computed mapping
function generateRelatedKeywordsFast(query: string): string[] {
    const suggestions: string[] = [];
    const queryWords = query.split(/\s+/);

    // Check if any word in query matches our map keys
    for (const word of queryWords) {
        if (RELATED_KEYWORDS_MAP[word]) {
            suggestions.push(...RELATED_KEYWORDS_MAP[word]);
        }
        // Also check for partial matches
        for (const [key, values] of Object.entries(RELATED_KEYWORDS_MAP)) {
            if (word.includes(key) || key.includes(word)) {
                suggestions.push(...values);
            }
        }
    }

    // If no matches, generate common patterns
    if (suggestions.length === 0) {
        suggestions.push(
            `${query} manager`,
            `${query} specialist`,
            `${query} coordinator`,
            `content ${query}`,
            `digital ${query}`,
            `${query} assistant`,
            `${query} executive`,
            `${query} lead`
        );
    }

    return [...new Set(suggestions)].slice(0, 8);
}

// Get popular searches based on job view counts
async function getPopularSearches() {
    try {
        // Get most viewed job titles as popular searches
        const popularJobs = await prisma.job.findMany({
            where: { status: "ACTIVE" },
            select: { title: true },
            distinct: ["title"],
            take: 5,
            orderBy: { viewCount: "desc" },
        });

        const suggestions: Array<{ type: string; value: string; label: string }> = [];

        popularJobs.forEach((job) => {
            suggestions.push({
                type: "keyword_suggestion",
                value: job.title,
                label: job.title,
            });
        });

        // Add popular industries
        const popularIndustries = await prisma.industry.findMany({
            take: 3,
        });

        popularIndustries.forEach((industry) => {
            suggestions.push({
                type: "industry",
                value: industry.name,
                label: industry.name,
            });
        });

        return suggestions.slice(0, 8);
    } catch (error) {
        console.error("Error getting popular searches:", error);
        return [];
    }
}
